contracts/ai.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/security/Pausable.sol";

contract StakingContract is Ownable, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    // Tokens
    //initializes tokens from IERC20 interface
    IERC20 public stakingToken;
    IERC20 public rewardToken;

    // Staking variables
    uint256 public rewardRate;//percentage of reward
    uint256 public lastUpdateTime;//assuming it is the last time the user staked
    uint256 public rewardPerTokenStored;//self explanatory
    uint256 public totalStaked;//self explanatory

    // Staking duration
    uint256 public stakingDuration = 1 minutes;//changed to shorter for testing

    // Maps
    mapping(address => uint256) public stakedBalance;//user id and staked amount
    mapping(address => uint256) public userRewardPerTokenPaid;//user id and reward amount
    mapping(address => uint256) public rewards;//user id and reward 
    mapping(address => uint256) public stakingTimestamp;//user id and the time stamp of the staking

    // Events
    event Staked(address indexed user, uint256 amount);
    event Withdrawn(address indexed user, uint256 amount);
    event RewardPaid(address indexed user, uint256 reward);
    event RewardRateUpdated(uint256 newRate);
    event StakingDurationUpdated(uint256 newDuration);

    constructor(
        address _stakingToken,//takes token address created for staking
        address _rewardToken,//takes token address created for rewards 
        uint256 _rewardRate//what is the reward rate?
    ) {
        //checks if the token address are not zero address, they are valid addresses
        require(_stakingToken != address(0), "Invalid staking token");
        require(_rewardToken != address(0), "Invalid reward token");

        //checks if the contract follows the ERC20 interface then assigns it to the state variables
        stakingToken = IERC20(_stakingToken);
        rewardToken = IERC20(_rewardToken);

        //how many token distributed to  stackers in a second
        rewardRate = _rewardRate;

        //to calculate the rewards of stakers
        lastUpdateTime = block.timestamp;

    }

    // Modifier to update rewards
    modifier updateReward(address account) {
        rewardPerTokenStored = rewardPerToken();
        lastUpdateTime = block.timestamp;

        if (account != address(0)) {
            rewards[account] = earned(account);
            userRewardPerTokenPaid[account] = rewardPerTokenStored;
        }
        _;
    }

    // Calculate reward per token
    function rewardPerToken() public view returns (uint256) {
        if (totalStaked == 0) {
            return rewardPerTokenStored;
        }
        return rewardPerTokenStored + ((block.timestamp - lastUpdateTime) * rewardRate * 1e18 / totalStaked);
    }

    // Calculate earned rewards for an account
    function earned(address account) public view returns (uint256) {
        return (stakedBalance[account] * (rewardPerToken() - userRewardPerTokenPaid[account]) / 1e18) + rewards[account];
    }

    // Stake tokens
    function stake(uint256 amount) external nonReentrant whenNotPaused updateReward(msg.sender) {
        require(amount > 0, "Cannot stake 0");

        stakedBalance[msg.sender] += amount;
        totalStaked += amount;
        stakingTimestamp[msg.sender] = block.timestamp;

        stakingToken.safeTransferFrom(msg.sender, address(this), amount);

        emit Staked(msg.sender, amount);
    }

    // Withdraw staked tokens
    function withdraw(uint256 amount) public nonReentrant updateReward(msg.sender) {
        require(amount > 0, "Cannot withdraw 0");
        require(stakedBalance[msg.sender] >= amount, "Insufficient balance");
        require(block.timestamp >= stakingTimestamp[msg.sender] + stakingDuration, "Still locked");

        stakedBalance[msg.sender] -= amount;
        totalStaked -= amount;

        stakingToken.safeTransfer(msg.sender, amount);

        emit Withdrawn(msg.sender, amount);
    }

    // Get reward
    function getReward() public nonReentrant updateReward(msg.sender) {
        uint256 reward = rewards[msg.sender];
        if (reward > 0) {
            rewards[msg.sender] = 0;
            rewardToken.safeTransfer(msg.sender, reward);
            emit RewardPaid(msg.sender, reward);
        }
    }

    // Withdraw and get reward in one transaction
    function withdrawAndGetReward() external {
        withdraw(stakedBalance[msg.sender]);
        getReward();
    }

    // Admin functions
    function setRewardRate(uint256 _rewardRate) external onlyOwner updateReward(address(0)) {
        rewardRate = _rewardRate;
        emit RewardRateUpdated(_rewardRate);
    }

    function setStakingDuration(uint256 _duration) external onlyOwner {
        stakingDuration = _duration;
        emit StakingDurationUpdated(_duration);
    }

    // Emergency withdraw (no rewards)
    function emergencyWithdraw() external nonReentrant {
        uint256 amount = stakedBalance[msg.sender];
        require(amount > 0, "No tokens staked");

        stakedBalance[msg.sender] = 0;
        totalStaked -= amount;

        stakingToken.safeTransfer(msg.sender, amount);

        emit Withdrawn(msg.sender, amount);
    }

    // Fund contract with rewards
    function fundRewards(uint256 amount) external onlyOwner {
        rewardToken.safeTransferFrom(msg.sender, address(this), amount);
    }

    // Pause/Unpause staking
    function pause() external onlyOwner {
        _pause();
    }

    function unpause() external onlyOwner {
        _unpause();
    }
}

contracts/multi_ai.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract TieredStaking is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    struct StakingTier {
        uint256 minAmount;
        uint256 maxAmount;
        uint256 rewardMultiplier; // In basis points (10000 = 100%)
        uint256 lockDuration;
        bool isActive;
    }

    struct StakeInfo {
        uint256 amount;
        uint256 tierId;
        uint256 stakedAt;
        uint256 lastClaimed;
        uint256 pendingRewards;
    }

    IERC20 public stakingToken;
    IERC20 public rewardToken;

    uint256 public baseRewardRate; // Tokens per second per token staked
    uint256 public totalStaked;

    mapping(uint256 => StakingTier) public tiers;
    uint256 public tierCount;

    mapping(address => StakeInfo[]) public userStakes;
    mapping(address => uint256) public totalUserStaked;

    event Staked(address indexed user, uint256 amount, uint256 tierId, uint256 stakeIndex);
    event Withdrawn(address indexed user, uint256 amount, uint256 stakeIndex);
    event RewardClaimed(address indexed user, uint256 amount, uint256 stakeIndex);
    event TierCreated(uint256 indexed tierId, uint256 minAmount, uint256 maxAmount, uint256 multiplier, uint256 lockDuration);
    event TierUpdated(uint256 indexed tierId, bool isActive);

    constructor(address _stakingToken, address _rewardToken, uint256 _baseRewardRate) {
        stakingToken = IERC20(_stakingToken);
        rewardToken = IERC20(_rewardToken);
        baseRewardRate = _baseRewardRate;
    }

    // Create a new staking tier
    function createTier(
        uint256 minAmount,
        uint256 maxAmount,
        uint256 rewardMultiplier,
        uint256 lockDuration
    ) external onlyOwner {
        require(minAmount < maxAmount, "Invalid amounts");
        require(rewardMultiplier > 0, "Invalid multiplier");

        tierCount++;
        tiers[tierCount] = StakingTier({
            minAmount: minAmount,
            maxAmount: maxAmount,
            rewardMultiplier: rewardMultiplier,
            lockDuration: lockDuration,
            isActive: true
        });

        emit TierCreated(tierCount, minAmount, maxAmount, rewardMultiplier, lockDuration);
    }

    // Update tier status
    function setTierStatus(uint256 tierId, bool isActive) external onlyOwner {
        require(tierId > 0 && tierId <= tierCount, "Invalid tier");
        tiers[tierId].isActive = isActive;
        emit TierUpdated(tierId, isActive);
    }

    // Stake tokens in a specific tier
    function stake(uint256 amount, uint256 tierId) external nonReentrant {
        require(tierId > 0 && tierId <= tierCount, "Invalid tier");
        StakingTier memory tier = tiers[tierId];
        require(tier.isActive, "Tier not active");
        require(amount >= tier.minAmount && amount <= tier.maxAmount, "Amount not in tier range");
        require(amount > 0, "Cannot stake 0");

        // Calculate if user has capacity in this tier
        uint256 userTierTotal = 0;
        for (uint i = 0; i < userStakes[msg.sender].length; i++) {
            if (userStakes[msg.sender][i].tierId == tierId) {
                userTierTotal += userStakes[msg.sender][i].amount;
            }
        }
        require(userTierTotal + amount <= tier.maxAmount, "Exceeds tier max");

        // Create new stake
        userStakes[msg.sender].push(StakeInfo({
            amount: amount,
            tierId: tierId,
            stakedAt: block.timestamp,
            lastClaimed: block.timestamp,
            pendingRewards: 0
        }));

        totalUserStaked[msg.sender] += amount;
        totalStaked += amount;

        stakingToken.safeTransferFrom(msg.sender, address(this), amount);

        emit Staked(msg.sender, amount, tierId, userStakes[msg.sender].length - 1);
    }

    // Calculate rewards for a specific stake
    function calculateRewards(address user, uint256 stakeIndex) public view returns (uint256) {
        StakeInfo memory stake = userStakes[user][stakeIndex];
        StakingTier memory tier = tiers[stake.tierId];

        uint256 timeStaked = block.timestamp - stake.lastClaimed;
        uint256 baseReward = stake.amount * baseRewardRate * timeStaked / 1e18;
        uint256 multipliedReward = baseReward * tier.rewardMultiplier / 10000;

        return multipliedReward + stake.pendingRewards;
    }

    // Claim rewards for a specific stake
    function claimRewards(uint256 stakeIndex) external nonReentrant {
        require(stakeIndex < userStakes[msg.sender].length, "Invalid stake");

        uint256 reward = calculateRewards(msg.sender, stakeIndex);
        require(reward > 0, "No rewards to claim");

        userStakes[msg.sender][stakeIndex].lastClaimed = block.timestamp;
        userStakes[msg.sender][stakeIndex].pendingRewards = 0;

        rewardToken.safeTransfer(msg.sender, reward);

        emit RewardClaimed(msg.sender, reward, stakeIndex);
    }

    // Withdraw a specific stake
    function withdrawStake(uint256 stakeIndex) external nonReentrant {
        require(stakeIndex < userStakes[msg.sender].length, "Invalid stake");

        StakeInfo memory stake = userStakes[msg.sender][stakeIndex];
        StakingTier memory tier = tiers[stake.tierId];

        require(block.timestamp >= stake.stakedAt + tier.lockDuration, "Stake still locked");

        // Calculate and pay pending rewards
        uint256 rewards = calculateRewards(msg.sender, stakeIndex);
        if (rewards > 0) {
            rewardToken.safeTransfer(msg.sender, rewards);
        }

        // Update totals
        totalUserStaked[msg.sender] -= stake.amount;
        totalStaked -= stake.amount;

        // Remove stake from array
        userStakes[msg.sender][stakeIndex] = userStakes[msg.sender][userStakes[msg.sender].length - 1];
        userStakes[msg.sender].pop();

        // Return staked tokens
        stakingToken.safeTransfer(msg.sender, stake.amount);

        emit Withdrawn(msg.sender, stake.amount, stakeIndex);
    }

    // Get user stakes
    function getUserStakes(address user) external view returns (StakeInfo[] memory) {
        return userStakes[user];
    }

    // Update base reward rate
    function setBaseRewardRate(uint256 newRate) external onlyOwner {
        baseRewardRate = newRate;
    }

    // Fund rewards
    function fundRewards(uint256 amount) external onlyOwner {
        rewardToken.safeTransferFrom(msg.sender, address(this), amount);
    }

    // Emergency withdraw without rewards
    function emergencyWithdraw(uint256 stakeIndex) external nonReentrant {
        require(stakeIndex < userStakes[msg.sender].length, "Invalid stake");

        uint256 amount = userStakes[msg.sender][stakeIndex].amount;

        totalUserStaked[msg.sender] -= amount;
        totalStaked -= amount;

        // Remove stake
        userStakes[msg.sender][stakeIndex] = userStakes[msg.sender][userStakes[msg.sender].length - 1];
        userStakes[msg.sender].pop();

        stakingToken.safeTransfer(msg.sender, amount);

        emit Withdrawn(msg.sender, amount, stakeIndex);
    }
}

contracts/My_Staking_Contract.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

//imports
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC721/IERC721.sol";//import for nft
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/security/Pausable.sol";

// I want to use the ai contract because it is easy to folllow, but I want to use the time contract because it is more secure
//user stakes NFT and after cooling time, user earns rewards, tokens or NFTs?
//simple route, stake NFT and get tokens as rewards, also considering rewarding ERC1155 NFTs in the future

contract My_Staking_Contract is Ownable, ReentrancyGuard, Pausable{
    using SafeERC20 for IERC20;

    IERC20 public rewardToken;
    IERC721 public stakingNFT;

    //user info
    struct User{
        uint256[] stakedTokenIds;
        uint256 rewards;
        uint256 lastClaimTime;
        uint256 stakedAt;
    }

    mapping(address => User) public userInfo;
    mapping(uint256 => address) public tokenOwner; 

    //contract info
    uint256 public totalStaked;
    uint256 public coolingTime;
    uint256 public rewardRate;

    //events
    event Staked(address indexed user, uint256 tokenId);
    event Withdrawn(address indexed user, uint256 tokenId);
    event RewardsClaimed(address indexed user, uint256 amount);
    event RewardRateUpdated(uint256 newRate);
    event StakingDurationUpdated(uint256 newDuration);



    constructor(
        address _stakingNFT,
        address _rewardToken,
        uint256 _coolingTime,
        uint256 _rewardRate
    ) Ownable() {
        require(_stakingNFT != address(0), "Invalid staking token");
        require(_rewardToken != address(0), "Invalid reward token");

        stakingNFT = IERC721(_stakingNFT);
        rewardToken = IERC20(_rewardToken);
        coolingTime = _coolingTime;
        rewardRate = _rewardRate;
    }

    // Modifier to update rewards
    modifier updateReward(address account) {
        if (account != address(0)) {
            userInfo[account].rewards = calculateRewards(account);
            userInfo[account].lastClaimTime = block.timestamp;
        }
        _;
    }


    //stake
    function stake(uint256 tokenId) external nonReentrant whenNotPaused updateReward(msg.sender) {
        require(tokenOwner[tokenId] == address(0), "NFT already staked");

        userInfo[msg.sender].stakedTokenIds.push(tokenId);
        tokenOwner[tokenId] = msg.sender;
        totalStaked++;

        if (userInfo[msg.sender].lastClaimTime == 0) {
            userInfo[msg.sender].lastClaimTime = block.timestamp;
        }
        userInfo[msg.sender].stakedAt = block.timestamp;

        stakingNFT.safeTransferFrom(msg.sender, address(this), tokenId);

        emit Staked(msg.sender, tokenId);
    }

    // Calculate rewards for a user
    function calculateRewards(address account) public view returns (uint256) {
        User memory user = userInfo[account];
        uint256 numNFTs = user.stakedTokenIds.length;
        if (numNFTs == 0) return user.rewards;

        uint256 timeStaked = block.timestamp - user.lastClaimTime;
        uint256 newRewards = numNFTs * rewardRate * timeStaked / 1e18;

        return newRewards + user.rewards;
    }

    function withdraw(uint256 tokenId) public nonReentrant whenNotPaused updateReward(msg.sender){
        require(tokenOwner[tokenId] == msg.sender, "Not your NFT");
        require(block.timestamp >= userInfo[msg.sender].stakedAt + coolingTime, "Still locked");

        _withdrawSingle(msg.sender, tokenId);
    }

    function withdrawAll() public  nonReentrant whenNotPaused updateReward(msg.sender){
        require(block.timestamp >= userInfo[msg.sender].stakedAt + coolingTime, "Still locked");

        uint256[] memory tokenIds = userInfo[msg.sender].stakedTokenIds;
        require(tokenIds.length > 0, "No NFTs to withdraw");

        for (uint256 i = tokenIds.length; i > 0; i--) {
            _withdrawSingle(msg.sender, tokenIds[i - 1]);
        }

        delete userInfo[msg.sender].stakedTokenIds;
    }

    function _withdrawSingle(address user, uint256 tokenId) internal {
        uint256[] storage stakedIds = userInfo[user].stakedTokenIds;
        for (uint256 i = 0; i < stakedIds.length; i++) {
            if (stakedIds[i] == tokenId) {
                stakedIds[i] = stakedIds[stakedIds.length - 1];
                stakedIds.pop();
                break;
            }
        }

        delete tokenOwner[tokenId];
        totalStaked--;
        stakingNFT.safeTransferFrom(address(this), user, tokenId);
        emit Withdrawn(user, tokenId);
    }

    function claimRewards() public  nonReentrant whenNotPaused updateReward(msg.sender){
        uint256 reward = userInfo[msg.sender].rewards;

        if (reward > 0) {
            userInfo[msg.sender].rewards = 0;
            rewardToken.safeTransfer(msg.sender, reward);
            emit RewardsClaimed(msg.sender, reward);
        }
    }

    function withdrawAllAndClaim() external {
        withdrawAll();
        claimRewards();
    }

    function withdrawAndClaim(uint256 tokenId) external {
        withdraw(tokenId);
        claimRewards();
    }

    function emergencyWithdrawAll() external nonReentrant {
        uint256[] memory tokenIds = userInfo[msg.sender].stakedTokenIds;
        require(tokenIds.length > 0, "No NFTs staked");

        for (uint256 i = tokenIds.length; i > 0; i--) {
            uint256 tokenId = tokenIds[i - 1];
            delete tokenOwner[tokenId];
            totalStaked--;
            stakingNFT.safeTransferFrom(address(this), msg.sender, tokenId);
            emit Withdrawn(msg.sender, tokenId);
        }

        delete userInfo[msg.sender].stakedTokenIds;
        delete userInfo[msg.sender].rewards;
        delete userInfo[msg.sender].lastClaimTime;
        delete userInfo[msg.sender].stakedAt;
    }

    function emergencyWithdraw(uint256 tokenId) external nonReentrant {
        require(tokenOwner[tokenId] == msg.sender, "Not your NFT");

        _withdrawSingle(msg.sender, tokenId);

        userInfo[msg.sender].rewards = 0;
    }

    //admin functions
    function fundRewards(uint256 amount) external onlyOwner {
        rewardToken.safeTransferFrom(msg.sender, address(this), amount);
    }

    function setRewardRate(uint256 _rewardRate) external onlyOwner updateReward(address(0)) {
        rewardRate = _rewardRate;
        emit RewardRateUpdated(_rewardRate);
    }

    function setCoolingTime(uint256 _duration) external onlyOwner {
        coolingTime = _duration;
        emit StakingDurationUpdated(_duration);
    }

    function pause() external onlyOwner {
        _pause();
    }

    function unpause() external onlyOwner {
        _unpause();
    }
}

